SELECT DISTINCT region_name
FROM regions
ORDER BY region_name;

SELECT COUNT(request_id) AS completed_requests_count
FROM projection_requests
WHERE request_status = 'completed';

SELECT region_id, MAX(created_at) AS latest_projection_date
FROM projections
GROUP BY region_id;

SELECT DISTINCT year
FROM projections
ORDER BY year ASC;

SELECT report_name
FROM projection_reports
WHERE report_date LIKE '2023-%';

SELECT projection_id, year, AVG(fit) OVER (PARTITION BY year) AS avg_fit
FROM projections
ORDER BY year DESC;

SELECT year
FROM projections
WHERE projection_id = 1;
